'use client';

import { useEffect, useState } from 'react';
import clsx from 'clsx';
import type { TocHeading } from '@/lib/blog-utils';

type BlogTableOfContentsProps = {
  headings: TocHeading[];
};

export default function BlogTableOfContents({ headings }: BlogTableOfContentsProps) {
  const [activeId, setActiveId] = useState<string>('');

  useEffect(() => {
    if (headings.length === 0) return;

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => a.boundingClientRect.top - b.boundingClientRect.top);
        if (visible[0]?.target.id) {
          setActiveId(visible[0].target.id);
        }
      },
      { rootMargin: '-80px 0px -70% 0px', threshold: 0 },
    );

    headings.forEach(({ id }) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, [headings]);

  if (headings.length < 2) return null;

  return (
    <nav aria-label="Table of contents" className="lg:sticky lg:top-28 pt-1">
      <p className="text-eyebrow text-brand-gold-600 mb-4">On this page</p>
      <ul className="space-y-2 border-l-2 border-navy-100 pl-4">
        {headings.map(({ id, text, level }) => (
          <li key={id}>
            <a
              href={`#${id}`}
              className={clsx(
                'block text-sm leading-snug transition-colors py-0.5',
                level === 3 && 'pl-3',
                activeId === id
                  ? 'text-brand-gold-600 font-semibold border-l-2 border-brand-gold-500 -ml-[calc(1rem+2px)] pl-[calc(1rem+2px-2px)]'
                  : 'text-navy-500 hover:text-brand-navy-800',
              )}
            >
              {text}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}
